#!/usr/bin/env julia
# Regenerate well-known type bindings from gen/proto/google/protobuf/*.proto.
# Output lands under gen/google/protobuf/ alongside the Phase 2 bootstrap
# files (descriptor_pb.jl, compiler/plugin_pb.jl). These WKTs are produced
# by *our* codegen, not the ProtoBuf.jl-bootstrapped path used for the
# descriptors — the goal is for as much of `gen/` as possible to be
# self-generated by the time Phase 8 lands.
#
# Usage (from repo root):
#     julia gen/regen_wkt.jl
#
# Requires `protoc` on PATH and the `bin/protoc-gen-julia` plugin script
# (already executable; the protoc invocation discovers it via --plugin=).
#
# All 11 WKTs are now generated by our own codegen.
#   Phase 7a (no inter-file deps):
#     any, duration, empty, field_mask, source_context, timestamp, wrappers
#   Phase 7b (cross-file imports through the codegen Universe):
#     api    — depends on source_context, type
#     type   — depends on any, source_context
#   Phase 7b (recursion via abstract supertypes):
#     struct — Value ↔ Struct ↔ ListValue cycle, broken by an
#              `abstract type` per participant plus a forwarding
#              `decode(::AbstractX)` method.

const HERE       = @__DIR__
const REPO       = dirname(HERE)
const PROTO_PATH = joinpath(HERE, "proto")
const OUT_DIR    = HERE  # protoc writes <julia_out>/google/protobuf/<name>_pb.jl
const PLUGIN     = joinpath(REPO, "bin", "protoc-gen-julia")

const WKT_PROTOS = [
    "google/protobuf/any.proto",
    "google/protobuf/duration.proto",
    "google/protobuf/empty.proto",
    "google/protobuf/field_mask.proto",
    "google/protobuf/source_context.proto",
    "google/protobuf/timestamp.proto",
    "google/protobuf/wrappers.proto",
    "google/protobuf/api.proto",
    "google/protobuf/type.proto",
    "google/protobuf/struct.proto",
]

function find_protoc()
    p = Sys.which("protoc")
    p === nothing && error("regen_wkt: `protoc` not found on PATH; install protobuf-compiler.")
    return p
end

function main()
    protoc = find_protoc()
    isfile(PLUGIN) || error("regen_wkt: plugin script missing at $(PLUGIN)")
    cmd = `$protoc --plugin=protoc-gen-julia=$PLUGIN --julia_out=$OUT_DIR --proto_path=$PROTO_PATH $WKT_PROTOS`
    run(cmd)
    for p in WKT_PROTOS
        out = joinpath(OUT_DIR, replace(p, r"\.proto$" => "_pb.jl"))
        println("wrote $(relpath(out, REPO))")
    end
end

main()
